CSS_PAGES = {"customer":"<style>.page-customer .memo-item{background:var(--bg-card);padding:16px 20px;margin-bottom:10px;border-radius:var(--radius-md);border:1px solid var(--border-light);border-left:4px solid var(--primary)}</style>","report":"<style>.page-report .report-wrap{background:var(--bg-card);padding:40px;border-radius:var(--radius-md);box-shadow:var(--shadow-md)}@media print{.page-report .report-wrap{box-shadow:none;padding:0}}</style>","bms":"<style>.page-bms .upload-zone{background:var(--bg-card);border:2px dashed var(--border-medium);border-radius:var(--radius-md);padding:var(--sp-2xl);text-align:center}</style>","login":"<style>.page-login [data-testid=\"stForm\"]{background:var(--bg-card)!important;border:1px solid var(--border-light)!important;border-radius:var(--radius-lg)!important;padding:48px 36px 32px!important;box-shadow:var(--shadow-lg)!important;max-width:420px;margin:0 auto}.page-login .login-footer{text-align:center;margin-top:20px;font-size:13px;color:var(--text-muted)}</style>"}
def inject_all_css():
    st.markdown(CSS_VARIABLES,unsafe_allow_html=True);st.markdown(CSS_GLOBAL,unsafe_allow_html=True)
def inject_page_css(k):
    css=CSS_PAGES.get(k,"");
    if css:st.markdown(css,unsafe_allow_html=True)
def page_wrapper_open(k):st.markdown(f'<div class="page-{k}">',unsafe_allow_html=True)
def page_wrapper_close():st.markdown('</div>',unsafe_allow_html=True)
def render_kpi(label,value,unit="건",color=None,variant=""):
    cs=f'color:{color};' if color else '';vc=f' crm-kpi--{variant}' if variant else ''
    return f'<div class="crm-kpi{vc}"><div class="crm-kpi-label">{label}</div><div class="crm-kpi-value" style="{cs}">{value}<span class="crm-kpi-unit">{unit}</span></div></div>'
def render_page_header(title,desc=""):
    d=f'<p>{desc}</p>' if desc else '';st.markdown(f'<div class="crm-page-header"><h1>{title}</h1>{d}</div>',unsafe_allow_html=True)
def render_section_title(text):st.markdown(f'<div class="crm-section-title">{text}</div>',unsafe_allow_html=True)
